#include<bits/stdc++.h>
using namespace std;
const int maxn = 5e5+5;
int n,m,a[maxn],ans=0,cntn=0;
bool b[maxn];
int fashe_x(int x)
{
	int cnt=0;
	int aa=x;
	
	if(b[0]==0)
	{
	    cnt++;
		cntn++;
		b[0]=1;	
	}		
	
	while(aa!=0)
	{
		if(b[aa]==0)
		{
			b[aa]=1;
			cnt++;cntn++;	
		}
		aa+=x;
		aa=aa%n;
	}
	return cnt;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int x;
		cin>>x;
		if(cntn==n)cout<<0<<" ";
		else 
		{
			ans=fashe_x(x%n);
		    cout<<ans<<" ";	
		}
	} 
	return 0;
}
